from typing import List

class Solution:
    def divideString(self, s: str, k: int, fill: str) -> List[str]:
        result = []
        for i in range(0, len(s), k):
            group = s[i:i+k]
            if len(group) < k:
                group += fill * (k - len(group))
            result.append(group)
        return result
```

This solution iterates over the string `s` in steps of `k`, creating groups of size `k`. If the last group is smaller than `k`, it appends the `fill` character enough times to make it of size `k`. The groups are collected in the `result` list, which is returned at the end.
